code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Badge } from 'decantr/components';

code.example:
function TechPillsStandard() {
  const { section, div, h3 } = tags;
  const techs = ['React', 'Next.js', 'Vue', 'Svelte', 'Claude', 'Cursor', 'Copilot', 'Windsurf'];

  return section({ class: css('_py20 _relative _z1') },
    div({ class: css('_container') },
      h3({ class: css('_heading3 _text[center] _fgmuted _mb6') }, 'Works With'),
      div({ class: css('_flex _flexwrap _justify[center] _gap3 _mw[700px] _mx[auto]') },
        techs.map(t =>
          Badge({ class: css('_rounded[20px] _py2 _px5 _fs[0.85rem] _fw600 _bgwhite/10 _fgwhite/80 _transition _hover:translateY[-2px]') }, t)
        )
      )
    )
  );
}

